import{_ as a,o as r,c as o,k as e,a as s,t as h,Q as n}from"./chunks/framework.1b6086f5.js";const P=JSON.parse('{"title":"3xx","description":"","frontmatter":{"title":"3xx"},"headers":[],"relativePath":"doc/网络协议/HTTP/状态码/3xx.md","filePath":"packages/doc/src/网络协议/HTTP/状态码/3xx.md","lastUpdated":1704643216000}'),p={name:"doc/网络协议/HTTP/状态码/3xx.md"},i={id:"frontmatter-title",tabindex:"-1"},c=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),d=n('<h2 id="_301-moved-permanently" tabindex="-1">301 <strong>Moved Permanently</strong> <a class="header-anchor" href="#_301-moved-permanently" aria-label="Permalink to &quot;301 **Moved Permanently**&quot;">​</a></h2><p>代表永久重定向</p><p>注意：对于某些使用HTTP/1.0协议的浏览器，当它们发送的POST请求得到了一个301响应的话，接下来的重定向请求将会变成GET方式。</p><h2 id="_3-302-found" tabindex="-1">3.302 Found <a class="header-anchor" href="#_3-302-found" aria-label="Permalink to &quot;3.302 Found&quot;">​</a></h2><p>代表临时重定向</p><p>请求的资源现在临时从不同的URI响应请求。由于这样的重定向是临时的，客户端应当继续向原有地址发送以后的请求。只有在Cache-Control或Expires中进行了指定的情况下，这个响应才是可缓存的。</p><p>注意：虽然RFC 1945和RFC 2068规范不允许客户端在重定向时改变请求的方法，但是很多现存的浏览器将302响应视作为303响应，并且使用GET方式访问在Location中规定的URI，而无视原先请求的方法。状态码303和307被添加了进来，用以明确服务器期待客户端进行何种反应。</p><p>在 <a href="https://zhangzifan.com/tags/post" target="_blank" rel="noreferrer">POST</a> 请求方式上，客户端收到服务端的 302 状态码，那么不能自动的向新的 URI 发送重复请求，必须跟用户确认是否该重发，因为第二次 POST 时，环境可能已经发生变化（POST 方法不是幂等），POST 操作会不符合用户预期。但是很多浏览器（user agent）在这种情况下都会把 POST 请求变为 <a href="https://zhangzifan.com/tags/get" target="_blank" rel="noreferrer">GET</a> 请求。</p><p>如果客户端发出非 GET、<a href="https://zhangzifan.com/tags/head" target="_blank" rel="noreferrer">HEAD</a> 请求后，收到服务端的 302 状态码，那么就不能自动的向新 URI 发送重复请求，除非得到用户的确认。但是，很多浏览器都把 302 当作 303 处理了（注意，303 是 HTTP1.1 才加进来的，其实从 HTTP1.0 进化到 HTTP1.1，浏览器什么都没动），它们获取到 HTTP 响应报文头部的 Location 字段信息，并发起一个 GET 请求。</p><h2 id="_4-303-see-other" tabindex="-1">4.303 See Other <a class="header-anchor" href="#_4-303-see-other" aria-label="Permalink to &quot;4.303 See Other&quot;">​</a></h2><p>对应当前请求的响应可以在另一个URI上被找到，而且客户端应当采用GET的方式访问那个资源。这个方法的存在主要是为了允许由脚本激活的POST请求输出重定向到一个新的资源。这个新的URI不是原始资源的替代引用。同时，303响应禁止被缓存。当然，第二个请求（重定向）可能被缓存。</p><p>新的URI应当在响应的Location域中返回。除非这是一个HEAD请求，否则响应的实体中应当包含指向新的URI的超链接及简短说明。</p><p>注意：许多HTTP/1.1版以前的浏览器不能正确理解303状态。如果需要考虑与这些浏览器之间的互动，302状态码应该可以胜任，因为大多数的浏览器处理302响应时的方式恰恰就是上述规范要求客户端处理303响应时应当做的。</p><h2 id="_5-304-not-modified-协商缓存" tabindex="-1">5.304 Not Modified 协商缓存 <a class="header-anchor" href="#_5-304-not-modified-协商缓存" aria-label="Permalink to &quot;5.304 Not Modified 协商缓存&quot;">​</a></h2><p>如果客户端发送了一个带条件的GET请求且该请求已被允许，而文档的内容（自上次访问以来或者根据请求的条件）并没有改变，则服务器应当返回这个状态码。304响应禁止包含消息体，因此始终以消息头后的第一个空行结尾。</p><p>该响应必须包含以下的头信息：</p><p>Date，除非这个服务器没有时钟。假如没有时钟的服务器也遵守这些规则，那么代理服务器以及客户端可以自行将Date字段添加到接收到的响应头中去（正如RFC 2068中规定的一样），缓存机制将会正常工作。</p><p>ETag和／或Content-Location，假如同样的请求本应返回200响应。</p><p>Expires, Cache-Control，和／或Vary，假如其值可能与之前相同变量的其他响应对应的值不同的话。</p><p>假如本响应请求使用了强缓存验证，那么本次响应不应该包含其他实体头；否则（例如，某个带条件的GET请求使用了弱缓存验证），本次响应禁止包含其他实体头；这避免了缓存了的实体内容和更新了的实体头信息之间的不一致。</p><p>假如某个304响应指明了当前某个实体没有缓存，那么缓存系统必须忽视这个响应，并且重复发送不包含限制条件的请求。</p><p>假如接收到一个要求更新某个缓存条目的304响应，那么缓存系统必须更新整个条目以反映所有在响应中被更新的字段的值。</p><h2 id="_5-307-temporary-redirect-hsts跳转" tabindex="-1">5.307 Temporary Redirect hsts跳转 <a class="header-anchor" href="#_5-307-temporary-redirect-hsts跳转" aria-label="Permalink to &quot;5.307 Temporary Redirect hsts跳转&quot;">​</a></h2><p>hsts全称HTTP<a href="https://www.zhihu.com/search?q=%E4%B8%A5%E6%A0%BC%E4%BC%A0%E8%BE%93%E5%AE%89%E5%85%A8&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22article%22%2C%22sourceId%22%3A%2234648453%22%7D" target="_blank" rel="noreferrer">严格传输安全</a>（HTTP Strict Transport Security，縮寫：HSTS），功能是要求浏览器下次访问该站点时使用https来访问，而不再需要先是http再转https。这样可以避免ssl剥离攻击，即攻击者在用户使用http访问的过程中进行攻击，对服务器冒充自己是用户，在攻击者和服务器中使用https访问，在用户和服务器中使用<a href="https://www.zhihu.com/search?q=http%E8%AE%BF%E9%97%AE&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22article%22%2C%22sourceId%22%3A%2234648453%22%7D" target="_blank" rel="noreferrer">http访问</a>。</p><p>具体使用方法是在服务器响应头中添加 Strict-Transport-Security，可以设置 <a href="https://www.zhihu.com/search?q=max-age&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22article%22%2C%22sourceId%22%3A%2234648453%22%7D" target="_blank" rel="noreferrer">max-age</a></p>',25);function l(t,_,T,m,f,u){return r(),o("div",null,[e("h1",i,[s(h(t.$frontmatter.title)+" ",1),c]),d])}const x=a(p,[["render",l]]);export{P as __pageData,x as default};
